import {
  CURSOR_MARKER,
  type Focusable,
  matchesKey,
} from "@earendil-works/pi-tui";
import type { Theme } from "@earendil-works/pi-coding-agent";
import type { PromptAction, PromptDialogOptions, PromptDialogResult } from "./types.js";

function visLen(s: string): number {
  let len = 0;
  const stripEsc = /\x1b\[[0-9;]*m/g;
  for (const ch of s.replace(stripEsc, "")) {
    const code = ch.codePointAt(0)!;
    if (
      (code >= 0x1100 && code <= 0x115f) ||  // Hangul Jamo
      (code >= 0x2e80 && code <= 0xa4cf) ||  // CJK
      (code >= 0xac00 && code <= 0xd7a3) ||  // Hangul Syllables
      (code >= 0xf900 && code <= 0xfaff) ||  // CJK Compatibility
      (code >= 0xfe30 && code <= 0xfe4f) ||  // CJK Compatibility Forms
      (code >= 0xff01 && code <= 0xff60) ||  // Fullwidth Forms
      (code >= 0x1f300 && code <= 0x1f9ff)    // Emoji
    ) {
      len += 2;
    } else {
      len += 1;
    }
  }
  return len;
}

// ── Component ────────────────────────────────────────────────────────────────

export class PromptDialogComponent<TAction extends string> implements Focusable {
  readonly width = 70;

  /** Focusable interface — set by TUI when focus changes */
  focused = false;

  private selected = 0;
  private actions: PromptAction<TAction>[];
  private inputConfig: PromptDialogOptions<TAction>["input"];
  private inputText = "";
  private inputCursor = 0;
  private inputFocused = false;
  private title: string;
  private description: string;

  private theme: Theme;
  private done: (result: PromptDialogResult<TAction>) => void;

  /** Total navigation items: actions + (optional) input row */
  private get itemCount(): number {
    return this.actions.length + (this.inputConfig ? 1 : 0);
  }

  constructor(
    options: PromptDialogOptions<TAction>,
    theme: Theme,
    done: (result: PromptDialogResult<TAction>) => void,
  ) {
    this.theme = theme;
    this.done = done;
    this.title = options.title;
    this.description = options.description || "";
    this.actions = options.actions;
    this.inputConfig = options.input;

    const defIdx = this.actions.findIndex((a) => a.default);
    this.selected = defIdx >= 0 ? defIdx : 0;
  }

  handleInput(data: string): void {
    // ── Global keys ──
    if (matchesKey(data, "escape")) {
      if (this.inputFocused) {
        this.inputFocused = false;
      } else {
        this.done(undefined);
      }
      return;
    }

    // ── Enter ──
    if (matchesKey(data, "return")) {
      if (this.inputFocused) {
        this.done({ type: "input", value: this.inputText });
      } else if (this.inputConfig && this.selected === this.actions.length) {
        // On input row → enter input mode
        this.inputFocused = true;
      } else {
        const action = this.actions[this.selected]!;
        this.done({ type: "action", action: action.id });
      }
      return;
    }

    // ── Tab → jump to input mode ──
    if (this.inputConfig && (data === "\t" || matchesKey(data, "tab"))) {
      if (!this.inputFocused) {
        this.inputFocused = true;
        return;
      }
    }

    // ── Navigation (not in input mode) ──
    if (!this.inputFocused) {
      if (matchesKey(data, "up")) {
        this.selected = Math.max(0, this.selected - 1);
        return;
      }
      if (matchesKey(data, "down")) {
        this.selected = Math.min(this.itemCount - 1, this.selected + 1);
        return;
      }
      // Right arrow on input row → enter input mode
      if (this.inputConfig && this.selected === this.actions.length && matchesKey(data, "right")) {
        this.inputFocused = true;
        return;
      }
    }

    // ── Input editing ──
    if (this.inputFocused) {
      if (matchesKey(data, "left")) {
        this.inputCursor = Math.max(0, this.inputCursor - 1);
        return;
      }
      if (matchesKey(data, "right")) {
        this.inputCursor = Math.min(this.inputText.length, this.inputCursor + 1);
        return;
      }
      if (matchesKey(data, "backspace")) {
        if (this.inputCursor > 0) {
          this.inputText =
            this.inputText.slice(0, this.inputCursor - 1) +
            this.inputText.slice(this.inputCursor);
          this.inputCursor--;
        }
        return;
      }
      if (matchesKey(data, "up")) {
        // Exit input mode → go back to navigation
        this.inputFocused = false;
        this.selected = this.actions.length;
        return;
      }
      // Printable char
      if (data.length === 1 && data.codePointAt(0)! >= 32) {
        this.inputText =
          this.inputText.slice(0, this.inputCursor) +
          data +
          this.inputText.slice(this.inputCursor);
        this.inputCursor++;
        return;
      }
    }
  }

  render(_width: number): string[] {
    const w = this.width;
    const th = this.theme;
    const innerW = w - 2;
    const lines: string[] = [];

    const pad = (s: string, len: number) => {
      const vis = visLen(s);
      return s + " ".repeat(Math.max(0, len - vis));
    };

    const row = (content: string) =>
      th.fg("border", "│") + pad(content, innerW) + th.fg("border", "│");

    const inputRowIndex = this.actions.length;

    // ── Top border + title ──
    lines.push(th.fg("border", `╭${"─".repeat(innerW)}╮`));
    lines.push(row(` ${th.fg("accent", th.bold ? th.bold(this.title) : this.title)}`));

    // ── Description ──
    if (this.description) {
      for (const descLine of this.description.split("\n")) {
        if (descLine.trim()) {
          lines.push(row(` ${th.fg("muted", descLine)}`));
        }
      }
    }

    lines.push(row(` ${th.fg("dim", "─".repeat(innerW - 2))}`));

    // ── Actions ──
    for (let i = 0; i < this.actions.length; i++) {
      const action = this.actions[i]!;
      const isSelected = i === this.selected && !this.inputFocused;
      const prefix = isSelected ? " ▶ " : "   ";
      const marker = action.default ? " * " : "";
      const label = isSelected
        ? th.fg("accent", `${marker}${action.label}`)
        : th.fg("text", `${marker}${action.label}`);
      lines.push(row(`${prefix}${label}`));
    }

    // ── Input row ──
    if (this.inputConfig) {
      const isSelected = this.selected === inputRowIndex && !this.inputFocused;
      const activeLine = isSelected || this.inputFocused;
      const prefix = isSelected ? " ▶ " : "   ";

      const labelText = activeLine
        ? th.fg("accent", `${this.inputConfig.label}:`)
        : th.fg("muted", `${this.inputConfig.label}:`);

      let inputDisplay: string;
      if (this.inputFocused) {
        const before = this.inputText.slice(0, this.inputCursor);
        const cursorChar =
          this.inputCursor < this.inputText.length
            ? this.inputText[this.inputCursor]!
            : " ";
        const after = this.inputText.slice(this.inputCursor + 1);
        const marker = this.focused ? CURSOR_MARKER : "";
        inputDisplay = `${before}${marker}\x1b[7m${cursorChar}\x1b[27m${after}`;
      } else {
        inputDisplay = this.inputText || th.fg("dim", this.inputConfig.placeholder || "");
      }

      lines.push(row(`${prefix}${labelText} ${inputDisplay}`));
    }

    // ── Footer ──
    const help =
      this.inputFocused
        ? `← → move cursor · ⌫ backspace · ↑ exit · Esc cancel · Enter submit`
        : `↑↓ navigate · Tab input · Enter select · Esc cancel`;
    lines.push(row(""));
    lines.push(row(` ${th.fg("dim", help)}`));
    lines.push(th.fg("border", `╰${"─".repeat(innerW)}╯`));

    return lines;
  }

  invalidate(): void {}
  dispose(): void {}
}
