// ── Types ────────────────────────────────────────────────────────────────────

/** A single action item in the prompt dialog. */
export interface PromptAction<TAction extends string = string> {
  /** Unique identifier for this action (e.g. "exit", "cancel"). */
  id: TAction;
  /** Human-readable label shown in the menu. */
  label: string;
  /** Whether this action is the default (Enter key immediately selects it). */
  default?: boolean;
}

/** Configuration for the optional inline input field. */
export interface PromptInput {
  /** Label shown before the input field (e.g. "补充指令"). */
  label: string;
  /** Placeholder text shown when input is empty. */
  placeholder?: string;
}

/** Options passed to showPromptDialog(). */
export interface PromptDialogOptions<TAction extends string = string> {
  /** Title shown at the top of the dialog. */
  title: string;
  /** Optional multi-line description / context (e.g. the blocked command). */
  description?: string;
  /** List of actions (1-10 items). */
  actions: PromptAction<TAction>[];
  /** Optional inline input field. When omitted, no input row is shown. */
  input?: PromptInput;
}

/** Discriminated union returned by showPromptDialog(). */
export type PromptDialogResult<TAction extends string = string> =
  | { type: "action"; action: TAction }
  | { type: "input"; value: string }
  | undefined;

// ── Validation ───────────────────────────────────────────────────────────────

export function validateOptions<TAction extends string>(
  options: PromptDialogOptions<TAction>,
): void {
  const { actions } = options;
  if (!actions || actions.length === 0) {
    throw new Error("At least one action is required.");
  }
  if (actions.length > 10) {
    throw new Error("Max 10 actions allowed.");
  }

  const ids = new Set<string>();
  for (const action of actions) {
    if (!action.id) throw new Error("Each action must have an id.");
    if (ids.has(action.id)) throw new Error(`Duplicate action id: "${action.id}".`);
    ids.add(action.id);
  }

  const defaults = actions.filter((a) => a.default).length;
  if (defaults > 1) throw new Error("Only one action can have default: true.");
}
