export { PromptDialogComponent } from "./prompt-dialog.js";
export {
  type PromptAction,
  type PromptInput,
  type PromptDialogOptions,
  type PromptDialogResult,
  validateOptions,
} from "./types.js";

import type { ExtensionContext } from "@earendil-works/pi-coding-agent";
import { PromptDialogComponent } from "./prompt-dialog.js";
import { type PromptDialogOptions, type PromptDialogResult, validateOptions } from "./types.js";

/**
 * Show a customizable prompt dialog overlay in pi's interactive TUI.
 *
 * The dialog displays a title, optional description, a list of actions (with
 * keyboard navigation), and an optional inline text input. It returns a
 * discriminated union so callers can narrow the result easily.
 *
 * @example
 * ```ts
 * const result = await showPromptDialog(ctx, {
 *   title: "Plan 模式拦截了此操作",
 *   description: "agent 想跑：npm install lodash",
 *   actions: [
 *     { id: "exit", label: "退出并执行", default: true },
 *     { id: "cancel", label: "取消" },
 *   ],
 *   input: { label: "补充指令", placeholder: "想让我怎么做？" },
 * });
 *
 * if (!result) {
 *   // Esc pressed
 * } else if (result.type === "action") {
 *   console.log("user chose:", result.action); // "exit" | "cancel"
 * } else {
 *   console.log("user typed:", result.value);
 * }
 * ```
 */
export async function showPromptDialog<TAction extends string>(
  ctx: ExtensionContext,
  options: PromptDialogOptions<TAction>,
): Promise<PromptDialogResult<TAction>> {
  validateOptions(options);

  if (!ctx.hasUI) {
    throw new Error(
      "showPromptDialog() requires an interactive UI (ctx.hasUI). " +
        "In headless / RPC mode, use ctx.ui.select() or ctx.ui.input() directly.",
    );
  }

  const result = await ctx.ui.custom<PromptDialogResult<TAction>>(
    (_tui, theme, _keybindings, done) =>
      new PromptDialogComponent(options, theme, done),
  );

  return result;
}
